#[test]
fn test_transformer_oracle_action_spec_language_neutral() {
    // Verify that action specs contain only JSON-primitive data â€” no Python
    // code, no lambda strings, no executable content.  This is the
    // "language-neutral" guarantee from the issue.
    let data = load_transformer_cases();
    let cases = data["cases"].as_array().unwrap();

    for case in cases {
        let name = case["name"].as_str().unwrap();
        for field in ["rule_actions", "token_actions"] {
            let actions = case[field].as_object().unwrap();
            for (action_name, action_spec) in actions {
                let obj = action_spec.as_object().unwrap();
                // Every key must be a string; every value must be a
                // JSON primitive (string, number, bool, null, array, object).
                // No "code", "lambda", "exec", "eval" keys allowed.
                let forbidden = ["code", "lambda", "exec", "eval", "python"];
                for key in obj.keys() {
                    assert!(
                        !forbidden.contains(&key.as_str()),
                        "case {name}.{field}.{action_name} has forbidden key {key:?} â€” \
                         action specs must be language-neutral"
                    );
                }
            }
        }
    }
}

// â”€â”€ C3: value + trace parity over every C1 fixture â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

/// The C3 gate: for **every** fixture case, the Python-shaped backend must
/// reproduce both the Python value JSON and the Python trace, under LALR + basic
/// and LALR + contextual.
#[test]
fn test_transformer_backend_value_and_trace_parity() {
    let data = load_transformer_cases();
    let cases = data["cases"].as_array().unwrap();

    let mut checked = 0usize;
    for case in cases {
        let name = case["name"].as_str().unwrap();
        for (config_key, lexer) in &CONFIGS {
            if let Err(e) = check_case_config(case, config_key, lexer.clone()) {
                panic!("case {name}:{config_key} failed parity:\n{e}");
            }
            checked += 1;
        }
    }
    assert!(checked > 0, "no fixture configs were checked");
}

/// Pin RFC Â§5: a kept terminal with **no** spec method must be materialized
/// silently (no trace entry), while a terminal *with* a method logs a visible
/// callback. `token_normalizer_upper` exercises both in one case: `NAME` has a
/// method (logged), `PUNCT` does not (kept silently as a Token value).
#[test]
fn test_engine_token_vs_visible_callback_distinction() {
    let data = load_transformer_cases();
    let cases = data["cases"].as_array().unwrap();
    let case = cases
        .iter()
        .find(|c| c["name"] == "token_normalizer_upper")
        .expect("token_normalizer_upper fixture present");

    let lark = build_lark(case, LexerType::Contextual).unwrap();
    let tree = lark.parse(case["input"].as_str().unwrap()).unwrap();
    let builder = PythonTransformerOracleBuilder::from_case(case);
    let (_value, trace) = builder.transform(&tree);

    // Only the NAME callbacks are visible; PUNCT is materialized silently.
    assert!(
        trace.iter().all(|t| t.name == "NAME" && t.kind == "token"),
        "expected only visible NAME token callbacks, got {trace:?}"
    );
    assert!(
        trace.iter().all(|t| t.name != "PUNCT"),
        "PUNCT has no spec method and must not produce a visible callback: {trace:?}"
    );
}

// â”€â”€ C4 (#229): the hardened parity edges, pinned individually â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

/// Find a fixture case by name, panicking if absent.
fn case_by_name<'a>(data: &'a Value, name: &str) -> &'a Value {
    data["cases"]
        .as_array()
        .unwrap()
        .iter()
        .find(|c| c["name"] == name)
        .unwrap_or_else(|| panic!("fixture case {name:?} is missing"))
}

/// C4 (d) â€” the RFC Â§5 open question, **settled by the fixture**: does the
/// *embedded* transformer path observe `__default_token__`? It does **not**.
/// Python's `_get_lexer_callbacks` only wires a terminal callback for terminals
/// the transformer defines an explicit method for, so the embedded path leaves a
/// default-handled token as a plain `Token` and never logs a `default_token`
/// trace entry â€” whereas the post-parse `.transform(tree)` path *does* invoke it.
/// The C3 backend reproduces the *post-parse* semantics; this test asserts the
/// committed fixture pins both sides of the divergence so a future embedded
/// `parse_into` backend (C7+) has a falsifiable target.
#[test]
fn test_default_token_embedded_vs_postparse_divergence() {
    let data = load_transformer_cases();
    let case = case_by_name(&data, "default_token_handler");

    for (config_key, lexer) in &CONFIGS {
        let cfg = &case["configs"][config_key];
        let postparse_trace = cfg["trace"].as_array().unwrap();
        let embedded = &cfg["embedded"];
        let embedded_trace = embedded["trace"].as_array().unwrap();

        let has_default_token = |trace: &[Value]| {
            trace
                .iter()
                .any(|e| e["kind"] == "default_token" && e["name"] == "NUMBER")
        };

        // Post-parse observes __default_token__ for NUMBERâ€¦
        assert!(
            has_default_token(postparse_trace),
            "{config_key}: post-parse trace must include a default_token entry for NUMBER"
        );
        // â€¦the embedded path does not.
        assert!(
            !has_default_token(embedded_trace),
            "{config_key}: embedded trace must NOT include a default_token entry \
             (RFC Â§5: embedded path does not wire __default_token__)"
        );
        // The values diverge too: post-parse converts NUMBER via the default
        // handler ("tok:42"); embedded keeps the raw Token.
        assert_eq!(
            cfg["value"][1],
            Value::String("tok:42".to_string()),
            "{config_key}: post-parse default-handles NUMBER"
        );
        assert_eq!(
            embedded["value"][1]["type"], "token",
            "{config_key}: embedded keeps NUMBER as a raw Token"
        );

        // The C3 (post-parse) backend must reproduce the post-parse trace.
        let lark = build_lark(case, lexer.clone()).unwrap();
        let tree = lark.parse(case["input"].as_str().unwrap()).unwrap();
        let (_v, trace) = PythonTransformerOracleBuilder::from_case(case).transform(&tree);
        assert!(
            trace
                .iter()
                .any(|t| t.kind == "default_token" && t.name == "NUMBER"),
            "{config_key}: C3 backend models the post-parse path and must log default_token"
        );
    }
}

/// C4 (a) â€” keyword/identifier `unless` retyping drives callback dispatch. The
/// string-literal keyword `IF` retypes a `NAME` match; the retyped `type_` is
/// what the transformer keys on, so `if` hits the `IF` method (prefix `kw:`) and
/// a plain identifier hits the `NAME` method (uppercase).
#[test]
fn test_unless_keyword_retype_dispatch() {
    let data = load_transformer_cases();
    let case = case_by_name(&data, "unless_keyword_retype");
    let lark = build_lark(case, LexerType::Contextual).unwrap();
    let tree = lark.parse(case["input"].as_str().unwrap()).unwrap();
    let (value, trace) = PythonTransformerOracleBuilder::from_case(case).transform(&tree);

    assert_eq!(value.to_json(), case["configs"]["lalr_contextual"]["value"]);
    // Both an IF callback (retyped keyword) and a NAME callback (identifier) fire.
    assert!(
        trace.iter().any(|t| t.kind == "token" && t.name == "IF"),
        "retyped keyword must dispatch to the IF method: {trace:?}"
    );
    assert!(
        trace.iter().any(|t| t.kind == "token" && t.name == "NAME"),
        "plain identifier must dispatch to the NAME method: {trace:?}"
    );
}

/// C4 (a) â€” an `%ignore`'d terminal never surfaces, so its callback never fires
/// even when a method for it exists.
#[test]
fn test_ignored_token_never_calls_back() {
    let data = load_transformer_cases();
    let case = case_by_name(&data, "ignored_token_no_callback");
    let lark = build_lark(case, LexerType::Basic).unwrap();
    let tree = lark.parse(case["input"].as_str().unwrap()).unwrap();
    let (value, trace) = PythonTransformerOracleBuilder::from_case(case).transform(&tree);

    // Value parity confirms the transform actually ran end-to-end (three
    // uppercased WORDs), so the negative trace check below is not vacuous.
    assert_eq!(value.to_json(), case["configs"]["lalr_basic"]["value"]);
    // The WORD callbacks DID fire (positive anchor) â€¦
    assert_eq!(
        trace.iter().filter(|t| t.name == "WORD").count(),
        3,
        "all three WORD callbacks must fire: {trace:?}"
    );
    // â€¦ while the ignored WS terminal never surfaces, so its method never runs.
    assert!(
        trace.iter().all(|t| t.name != "WS"),
        "an ignored WS terminal must never produce a callback: {trace:?}"
    );
}

/// C4 (b) â€” `Discard` from a token callback under `maybe_placeholders`: a
/// PRESENT optional that the callback discards is removed entirely (no `None`
/// hole), distinct from the `None` placeholder inserted for an ABSENT optional.
#[test]
fn test_discard_token_under_maybe_placeholders() {
    let data = load_transformer_cases();

    // Present-and-discarded: result is [a, c] â€” no hole left at B's slot.
    let present = case_by_name(&data, "discard_token_maybe_placeholders");
    let lark = build_lark(present, LexerType::Basic).unwrap();
    let tree = lark.parse(present["input"].as_str().unwrap()).unwrap();
    let (value, _t) = PythonTransformerOracleBuilder::from_case(present).transform(&tree);
    assert_eq!(
        value.to_json(),
        serde_json::json!(["a", "c"]),
        "a discarded PRESENT optional leaves no placeholder hole"
    );

    // Absent: maybe_placeholders inserts a None at B's slot, B callback silent.
    let absent = case_by_name(&data, "discard_token_maybe_placeholders_absent");
    let lark = build_lark(absent, LexerType::Basic).unwrap();
    let tree = lark.parse(absent["input"].as_str().unwrap()).unwrap();
    let (value, trace) = PythonTransformerOracleBuilder::from_case(absent).transform(&tree);
    assert_eq!(
        value.to_json(),
        serde_json::json!(["a", null, "c"]),
        "an ABSENT optional yields a None placeholder under maybe_placeholders"
    );
    // Positive anchor: the A and C callbacks DID fire, so the negative B check
    // below cannot pass vacuously on an empty trace.
    assert!(
        trace.iter().any(|t| t.name == "A") && trace.iter().any(|t| t.name == "C"),
        "the A and C callbacks must fire: {trace:?}"
    );
    assert!(
        trace.iter().all(|t| t.name != "B"),
        "the B callback must not fire for an absent optional: {trace:?}"
    );
}

// â”€â”€ Content pins (not just schema) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
//
// The schema tests above check fixture *shape*. These pin fixture *content* â€” the
// transformed value and the exact callback trace â€” so the fixture's semantic
// claims (arithmetic result, bottom-up callback order, Token-before-str
// serialization, language-neutral output) cannot silently drift. Until a Rust
// transformer exists these guard the generator + freshness gate; once it lands the
// same expectations become the replay target.

/// Recursively visit every JSON string within `v`.
fn for_each_string(v: &Value, f: &mut impl FnMut(&str)) {
    match v {
        Value::String(s) => f(s),
        Value::Array(a) => a.iter().for_each(|x| for_each_string(x, f)),
        Value::Object(o) => o.values().for_each(|x| for_each_string(x, f)),
        _ => {}
    }
}

/// Recursively visit every serialized value-node (a JSON object with a `type` tag).
fn for_each_typed_node(v: &Value, f: &mut impl FnMut(&str, &serde_json::Map<String, Value>)) {
    match v {
        Value::Array(a) => a.iter().for_each(|x| for_each_typed_node(x, f)),
        Value::Object(o) => {
            if let Some(Value::String(t)) = o.get("type") {
                f(t, o);
            }
            o.values().for_each(|x| for_each_typed_node(x, f));
        }
        _ => {}
    }
}

/// Assert a trace's ordered `(kind, name)` sequence equals `expected`.
fn assert_trace_eq(trace: &Value, expected: &[(&str, &str)], label: &str) {
    let got: Vec<(String, String)> = trace
        .as_array()
        .unwrap_or_else(|| panic!("{label}: trace is not an array"))
        .iter()
        .map(|e| {
            (
                e["kind"].as_str().unwrap_or("?").to_string(),
                e["name"].as_str().unwrap_or("?").to_string(),
            )
        })
        .collect();
    let exp: Vec<(String, String)> = expected
        .iter()
        .map(|(k, n)| (k.to_string(), n.to_string()))
        .collect();
    assert_eq!(got, exp, "{label}: callback trace order mismatch");
}

#[test]
fn test_transformer_oracle_pins_canonical_value_and_trace() {
    let data = load_transformer_cases();

    // arithmetic_eval: the bottom-up evaluator must compute 2 + 3*4 = 14, with the
    // exact bottom-up callback order. Pins evaluation semantics AND order â€” result
    // equality alone would miss a permuted trace (#226's non-negotiable).
    let arith = case_by_name(&data, "arithmetic_eval");
    let arith_trace = [
        ("token", "NUMBER"),
        ("rule", "factor"),
        ("rule", "term"),
        ("token", "NUMBER"),
        ("rule", "factor"),
        ("token", "NUMBER"),
        ("rule", "factor"),
        ("rule", "term"),
        ("rule", "expr"),
        ("rule", "start"),
    ];
    for (cfg, v) in arith["configs"].as_object().unwrap() {
        assert_eq!(
            v["value"].as_i64(),
            Some(14),
            "arithmetic_eval[{cfg}]: value must be 14"
        );
        assert_trace_eq(
            &v["trace"],
            &arith_trace,
            &format!("arithmetic_eval[{cfg}]"),
        );
    }

    // callback_order_trace: the exact bottom-up (kind, name) order, and Tokens
    // serialized as tagged `token` nodes (the Token-before-str fix) â€” never bare
    // strings. A regression of either is caught here, not just by the freshness diff.
    let cb = case_by_name(&data, "callback_order_trace");
    let cb_trace = [
        ("token", "A"),
        ("token", "B"),
        ("rule", "first"),
        ("token", "C"),
        ("rule", "second"),
        ("rule", "start"),
    ];
    for (cfg, v) in cb["configs"].as_object().unwrap() {
        assert_trace_eq(
            &v["trace"],
            &cb_trace,
            &format!("callback_order_trace[{cfg}]"),
        );
        let mut token_nodes = 0usize;
        for_each_typed_node(&v["value"], &mut |t, o| {
            if t == "token" {
                token_nodes += 1;
                assert!(
                    o.get("token_type").and_then(Value::as_str).is_some(),
                    "callback_order_trace[{cfg}]: token node missing string token_type"
                );
                assert!(
                    o.get("value").and_then(Value::as_str).is_some(),
                    "callback_order_trace[{cfg}]: token node missing string value (Token bare-stringified?)"
                );
            }
        });
        assert!(
            token_nodes >= 3,
            "callback_order_trace[{cfg}]: expected â‰Ą3 serialized Token nodes, got {token_nodes}"
        );
    }
}

#[test]
fn test_transformer_oracle_values_well_formed_and_neutral() {
    let data = load_transformer_cases();
    let cases = data["cases"].as_array().unwrap();

    // Python-object-repr signatures that must never appear in serialized output â€”
    // these would mean a value/trace leaked a non-portable Python object instead of
    // a JSON primitive or a tagged node. Extends the language-neutral guarantee from
    // the action specs (which the generator authored) to the captured output (which
    // it did not), closing the circularity gap.
    let leakage = [
        " object at 0x",
        "<function",
        "<lambda",
        "<bound method",
        "<lark.",
    ];

    for case in cases {
        let name = case["name"].as_str().unwrap();
        for (cfg, v) in case["configs"].as_object().unwrap() {
            if v["status"].as_str() != Some("ok") {
                continue;
            }
            // Every typed node is a well-formed token/tree/unknown; a token node
            // carries string token_type + value (Token is never bare-stringified).
            for_each_typed_node(&v["value"], &mut |t, o| {
                assert!(
                    matches!(t, "token" | "tree" | "unknown"),
                    "{name}[{cfg}]: value has unknown type tag {t:?}"
                );
                if t == "token" {
                    assert!(
                        o.get("token_type").and_then(Value::as_str).is_some(),
                        "{name}[{cfg}]: token node missing string token_type"
                    );
                    assert!(
                        o.get("value").and_then(Value::as_str).is_some(),
                        "{name}[{cfg}]: token node missing string value"
                    );
                }
            });
            for field in ["value", "trace"] {
                for_each_string(&v[field], &mut |s| {
                    for sig in leakage {
                        assert!(
                            !s.contains(sig),
                            "{name}[{cfg}].{field}: Python-repr leakage {sig:?} in {s:?} â€” \
                             serialized output must be language-neutral"
                        );
                    }
                });
            }
        }
    }
}
